				theme.fg("accent", args.team || "unknown") +
				theme.fg("muted", ` [${execution} ┬Ę ${mode} ┬Ę ${launchBackend}]`) +
				theme.fg("dim", ` ┬Ę ${queries.length} quer${queries.length === 1 ? "y" : "ies"}`),
				0,

[196 more lines in file. Use offset=2520 to continue.]

